\chapter{불변부분공간과 적합기저}

\chapterintro{이 장에서는 유한차원 벡터 공간과 선형 변환을 다루며, 불변부분공간과 적합기저에 관한 기본 개념과 정리를 소개합니다.}{주요 목표는 불변부분공간의 정의를 이해하고, 적합기저 존재 정리를 증명하는 것입니다.}

\sectiontemplate{불변부분공간의 정의}{유한차원 벡터 공간 $F$와 선형 변환 $T$가 주어졌을 때, 불변부분공간의 개념을 정의합니다.}{불변부분공간은 $T$에 대해 닫힌 부분공간으로, $T(v) \in W$가 모든 $v \in W$에 대해 성립하는 부분공간 $W$를 의미합니다.}{}

\begin{definition}[불변부분공간]
$F$를 유한차원 벡터 공간, $T: F \to F$를 선형 변환이라 하자. 부분공간 $W \subseteq F$가 임의의 $v \in W$에 대해 $T(v) \in W$를 만족하면, $W$를 $T$에 대한 불변부분공간이라 한다.
\end{definition}

\begin{theorem}[불변부분공간의 기본 성질]
불변부분공간은 부분공간의 교집합에 대해 닫혀 있으며, $T$에 관한 여러 성질을 가진다.
\end{theorem}

\begin{proof}
\begin{enumerate}
    \item 여러 불변부분공간의 교집합 또한 불변부분공간임을 보인다.
    \item 정의대로 선형 변환 $T$가 교집합 내 임의 원소에 작용해 그 안에 머무는지 확인한다.
\end{enumerate}
\end{proof}

\sectiontemplate{적합기저 (적합한 기저)}{적합기저의 정의와 존재에 대해 서술한다.}{적합기저는 주어진 선형 변환에 대해 행렬 표현을 가능한 단순한 형태로 만드는 기저이다.}{}

\begin{definition}[적합기저]
$F$와 $T$가 앞선 조건을 만족할 때, $T$에 대해 불변부분공간들의 적절한 조합으로 만들어진 기저를 적합기저라 한다.
\end{definition}

\begin{theorem}[적합기저 존재 정리]
모든 유한차원 벡터 공간 $F$와 선형 변환 $T: F \to F$에 대해 적합기저가 존재한다.
\end{theorem}

\begin{proof}
\begin{enumerate}
    \item 유한차원임을 이용해 귀납법으로 구성한다.
    \item 불변부분공간과 그补공간을 적절히 선택하여 기저를 만든다.
    \item 각 단계별로 $T$가 표현되는 행렬의 형태가 적합함을 확인한다.
\end{enumerate}
\end{proof}
